<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    SimpleApplicationEventMulticaster multicaster </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> SimpleApplicationEventMulticaster</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
